query:
SELECT COUNT(*) as userCount FROM users;
SELECT COUNT(*) as songCount FROM songs WHERE status != 'Deleted';
SELECT COUNT(*) as widCount FROM songs WHERE witnessId IS NOT NULL AND status != 'Deleted';
SELECT u.id, u.name, COUNT(s.id) as trackCount FROM users u LEFT JOIN songs s ON s.userId = u.id AND s.status != 'Deleted' GROUP BY u.id LIMIT 5;

